mapper.select:
SELECT id, user1_id, user2_id, last_message, last_msg_at, created_at
FROM chat_conversation
WHERE id = #{id}

mapper.update:
UPDATE chat_conversation
SET last_message = #{lastMessage}, last_msg_at = #{lastMsgAt}
WHERE id = #{id}

mapper.select:
SELECT id, conversation_id, sender_id, receiver_id, content, is_read, created_at
FROM chat_message
WHERE conversation_id = #{conversationId}
ORDER BY created_at ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM chat_message
WHERE conversation_id = #{conversationId}
  AND receiver_id = #{receiverId}
  AND is_read = 0

mapper.update:
UPDATE chat_message
SET is_read = 1
WHERE conversation_id = #{conversationId}
  AND receiver_id = #{receiverId}
  AND is_read = 0
